import { useEffect, useState } from "react"
import ScannerQr from "src/components/ScannerQr"
import SvgIcon from "src/components/SvgIcon"
import listSVGIcon from "src/components/SvgIcon/icons"
import styled from "styled-components"

const IconWrapper = styled.span`
  z-index: 2;

  svg {
    width: auto;
    height: auto;
  }
`
const SvgViewer = () => {
  const [listIconView, setListIconView] = useState([])
  useEffect(() => {
    let ListIcon = []
    for (const key in listSVGIcon) {
      ListIcon.push(key)
    }
    setListIconView(ListIcon)
  }, [])

  return (
    <>
      <ScannerQr />

      <div className="p-10" style={{ background: "#fff" }}>
        <div
          style={{
            display: "flex",
            gap: "10px",
            flexWrap: "wrap",
            paddingBottom: 50,
          }}
        >
          {listIconView.map((ele, idx) => (
            <div key={idx}>
              <IconWrapper>
                <SvgIcon name={ele} />
                <span>{ele}</span>
              </IconWrapper>
            </div>
          ))}
        </div>
      </div>
    </>
  )
}

export default SvgViewer
